      "func": {
        "valueRef": {
          "path": "target_ip"
        }
      }
    },
    {
      "from": "data",
      "to": "name",
      "func": {
        "valueRef": {
          "path": "name"
        }
      }
    },
    {
      "to": "metric_name",
